import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

class CSVFormatTest {

    @Test
    void testWithCommentMarkerChar() {
        CSVFormat original = CSVFormat.DEFAULT;
        char commentChar = '#';

        CSVFormat updated = original.withCommentMarker(commentChar);

        assertNotNull(updated);
        assertNotSame(original, updated);
        assertEquals(Character.valueOf(commentChar), updated.getCommentMarker());
    }

    @Test
    void testWithCommentMarkerCharNull() {
        CSVFormat original = CSVFormat.DEFAULT.withCommentMarker('#');
        char commentChar = '\0';

        CSVFormat updated = original.withCommentMarker(commentChar);

        assertNotNull(updated);
        assertNotSame(original, updated);
        // If '\0' is passed, it should be boxed and passed to withCommentMarker(Character)
        // The behavior depends on implementation of withCommentMarker(Character)
        // We check that commentMarker is set to '\0'
        assertEquals(Character.valueOf('\0'), updated.getCommentMarker());
    }
}
